import type { Message } from '../providers/types.js';
import type { ToolCallRequest } from '../tools/types.js';
import type { AgentRunOptions, AgentRunResult } from './types.js';
import { Executor } from './Executor.js';
import { compressHistory } from '../context/MemoryCompressor.js';
import { logger } from '../utils/logger.js';

const DEFAULT_MAX_TOOL_OUTPUT_CHARS = 32_768;
const DEFAULT_AUTO_COMPRESS_AT = 80_000;
const DEFAULT_MAX_OUTPUT_TOKENS = 16_384;

/**
 * AgentRunner executes the ReAct agent loop.
 *
 * Remote constraints should be loaded before session start and injected into the
 * system prompt via ContextBuilder. See ConstraintLoader for fetching constraints
 * from the backend at GET /v1/projects/{id}/constraints.
 */

function estimateTokens(messages: Message[]): number {
  let chars = 0;
  for (const m of messages) {
    if (typeof m.content === 'string') {
      chars += m.content.length;
    } else {
      chars += JSON.stringify(m.content).length;
    }
  }
  return Math.ceil(chars / 4);
}

function truncateToolOutput(content: string, limit: number): string {
  if (content.length <= limit) return content;
  const kept = content.slice(0, limit);
  const droppedChars = content.length - limit;
  return `${kept}\n\n[truncated — showing first ${limit.toLocaleString()} of ${content.length.toLocaleString()} chars (${droppedChars.toLocaleString()} dropped)]`;
}

export class AgentRunner {
  private executor: Executor;
  private iterationCount = 0;
  private totalInputTokens = 0;
  private totalOutputTokens = 0;
  private totalToolCalls = 0;
  private maxToolOutputChars: number;

  constructor(private options: AgentRunOptions) {
    this.executor = new Executor({
      tools: options.tools,
      dangerousSkipApproval: options.dangerousSkipApproval ?? false,
      maxConcurrency: 3,
    });
    this.maxToolOutputChars = options.maxToolOutputChars ?? DEFAULT_MAX_TOOL_OUTPUT_CHARS;
  }

  async run(): Promise<AgentRunResult> {
    const maxIterations = this.options.maxIterations ?? 20;
    const autoCompressAt = this.options.autoCompressAt ?? DEFAULT_AUTO_COMPRESS_AT;

    let messages: Message[] = [
      ...(this.options.history ?? []),
      { role: 'user', content: this.options.userMessage },
    ];

    let finalResponse = '';

    while (this.iterationCount < maxIterations) {
      this.iterationCount++;
      this.options.onIterationStart?.(this.iterationCount);

      logger.debug({ iteration: this.iterationCount }, 'Agent iteration');

      // Auto-compress if history has grown past threshold
      if (estimateTokens(messages) > autoCompressAt && messages.length > 6) {
        try {
          logger.debug('Auto-compressing conversation history');
          messages = await compressHistory(
            messages,
            this.options.provider,
            this.options.model,
          );
        } catch {
          logger.warn('Auto-compression failed, continuing with full history');
        }
      }

      let accumulatedText = '';

      const response = await this.options.provider.stream(
        {
          messages,
          systemPrompt: this.options.systemPrompt,
          tools: this.options.tools.map(t => t.definition),
          model: this.options.model,
          stream: true,
          maxTokens: this.options.maxOutputTokens ?? DEFAULT_MAX_OUTPUT_TOKENS,
        },
        delta => {
          if (delta.type === 'text_delta') {
            this.options.onTextDelta?.(delta.text);
            accumulatedText += delta.text;
          }
        }
      );

      this.totalInputTokens += response.usage.inputTokens;
      this.totalOutputTokens += response.usage.outputTokens;

      // Budget enforcement — check after every LLM response
      if (this.options.budgetGuard) {
        const check = this.options.budgetGuard.recordUsage(
          response.usage.inputTokens,
          response.usage.outputTokens,
        );
        if (check.action !== 'ok') {
          this.options.onBudgetCheck?.(check);
        }
        if (check.action === 'pause') {
          // Hard stop — append what we have and return immediately
          messages.push({ role: 'assistant', content: response.content });
          return this.buildResult(
            response.content.filter(p => p.type === 'text').map(p => p.text ?? '').join('') || check.message,
            messages,
          );
        }
      }

      const toolUses = response.content.filter(p => p.type === 'tool_use');
      const textParts = response.content.filter(p => p.type === 'text');

      if (textParts.length > 0 || accumulatedText) {
        finalResponse = textParts.map(p => p.text ?? '').join('') || accumulatedText;
      }

      if (response.stopReason === 'end_turn' || toolUses.length === 0) {
        // Append the final assistant message so messages array is complete
        messages.push({ role: 'assistant', content: response.content });

        // Run auditor review if configured
        if (this.options.onAuditorReview && finalResponse) {
          const shouldProceed = await this.options.onAuditorReview(
            this.options.userMessage,
            finalResponse,
            messages,
          );
          if (!shouldProceed) {
            // Auditor blocked the response - return empty result
            return this.buildResult('[Response blocked by auditor review]', messages);
          }
        }

        break;
      }

      if (response.stopReason === 'max_tokens') {
        // Model ran out of output tokens mid-generation — push what we have
        // and continue the loop so the model can pick up where it left off.
        logger.debug('max_tokens hit — continuing conversation');
        messages.push({ role: 'assistant', content: response.content });
        messages.push({ role: 'user', content: 'Continue from where you left off.' });
        continue;
      }

      const toolCallRequests: ToolCallRequest[] = toolUses.map(p => ({
        id: p.id ?? '',
        name: p.name ?? '',
        input: (p.input as Record<string, unknown>) ?? {},
      }));

      this.totalToolCalls += toolCallRequests.length;
      this.options.onToolCall?.(
        toolCallRequests.map(r => r.name).join(', '),
        toolCallRequests[0]?.input ?? {}
      );

      const toolResults = await this.executor.executeAll(toolCallRequests);

      for (const result of toolResults) {
        result.content = truncateToolOutput(result.content, this.maxToolOutputChars);

        this.options.onToolResult?.(
          toolCallRequests.find(r => r.id === result.toolUseId)?.name ?? '',
          result.content,
          result.isError
        );
      }

      messages.push({
        role: 'assistant',
        content: response.content,
      });

      messages.push({
        role: 'tool',
        content: toolResults.map(r => ({
          type: 'tool_result' as const,
          tool_use_id: r.toolUseId,
          content: r.content,
        })),
      });
    }

    if (this.iterationCount >= maxIterations && !finalResponse) {
      finalResponse = `Agent reached maximum iterations (${maxIterations}) without completing.`;
    }

    return this.buildResult(finalResponse, messages);
  }

  private buildResult(finalResponse: string, messages: Message[]): AgentRunResult {
    return {
      finalResponse,
      toolCallCount: this.totalToolCalls,
      iterations: this.iterationCount,
      usage: {
        inputTokens: this.totalInputTokens,
        outputTokens: this.totalOutputTokens,
      },
      messages,
    };
  }
}

import { readFile } from 'fs/promises';
import { join } from 'path';
import { existsSync } from 'fs';
import type { AuditorConfig } from './types.js';
import { logger } from '../utils/logger.js';

/**
 * AuditorRegistry loads and manages auditor personas from .epam/auditors.json
 */
export class AuditorRegistry {
  private auditors: AuditorConfig[] = [];
  private enabled = false;

  constructor(private projectRoot: string) {}

  async load(): Promise<void> {
    const configPath = join(this.projectRoot, '.epam', 'auditors.json');

    if (!existsSync(configPath)) {
      logger.debug({ configPath }, 'No auditors.json found — auditors disabled');
      this.auditors = [];
      return;
    }

    try {
      const content = await readFile(configPath, 'utf-8');
      const config = JSON.parse(content);

      if (!Array.isArray(config.auditors)) {
        logger.warn('auditors.json missing "auditors" array — skipping');
        this.auditors = [];
        return;
      }

      this.auditors = config.auditors.filter((a: AuditorConfig) => {
        // Validate required fields
        if (!a.name || !a.persona || !a.focus || !a.severity_threshold || !a.model) {
          logger.warn({ auditor: a.name }, 'Invalid auditor config — skipping');
          return false;
        }
        return true;
      });

      logger.debug({ count: this.auditors.length }, 'Loaded auditor personas');
    } catch (error) {
      logger.warn({ error, configPath }, 'Failed to load auditors.json');
      this.auditors = [];
    }
  }

  getAll(): AuditorConfig[] {
    return this.auditors;
  }

  getEnabled(): AuditorConfig[] {
    if (!this.enabled) return [];
    return this.auditors.filter(a => a.enabled !== false);
  }

  toggle(enable: boolean): void {
    this.enabled = enable;
  }

  isEnabled(): boolean {
    return this.enabled;
  }

  hasAuditors(): boolean {
    return this.auditors.length > 0;
  }
}

import type { Message } from '../providers/types.js';

export type SeverityLevel = 'info' | 'warning' | 'critical';

export interface AuditorConfig {
  name: string;
  persona: string;
  focus: string;
  severity_threshold: SeverityLevel;
  model: string;
  enabled?: boolean;
}

export interface AuditorFinding {
  auditorName: string;
  severity: SeverityLevel;
  finding: string;
}

export interface AuditorResult {
  auditorName: string;
  findings: AuditorFinding[];
  /** Full transcript of the auditor's critique */
  transcript: string;
  severity: SeverityLevel;
}

export interface AuditorInput {
  /** The user's original message */
  userMessage: string;
  /** The agent's proposed response */
  proposedResponse: string;
  /** Full conversation context */
  conversationHistory: Message[];
}

import type { LLMProvider } from '../providers/types.js';
import type { Tool } from '../tools/types.js';
import type {
  AuditorConfig,
  AuditorInput,
  AuditorResult,
  AuditorFinding,
  SeverityLevel,
} from './types.js';
import { AgentRunner } from '../agent/AgentRunner.js';
import { logger } from '../utils/logger.js';

/**
 * AuditorRunner executes auditor agents in parallel and collects their critiques
 */
export class AuditorRunner {
  constructor(
    private provider: LLMProvider,
    private tools: Tool[],
  ) {}

  /**
   * Run all enabled auditors in parallel and collect their findings
   */
  async runAuditors(
    auditors: AuditorConfig[],
    input: AuditorInput,
  ): Promise<AuditorResult[]> {
    if (auditors.length === 0) return [];

    logger.debug({ auditorCount: auditors.length }, 'Running auditors in parallel');

    // Execute all auditors in parallel
    const results = await Promise.all(
      auditors.map(auditor => this.runSingleAuditor(auditor, input)),
    );

    return results;
  }

  private async runSingleAuditor(
    auditor: AuditorConfig,
    input: AuditorInput,
  ): Promise<AuditorResult> {
    try {
      const systemPrompt = this.buildAuditorSystemPrompt(auditor);
      const userPrompt = this.buildAuditorUserPrompt(input);

      const runner = new AgentRunner({
        userMessage: userPrompt,
        systemPrompt,
        provider: this.provider,
        model: auditor.model,
        tools: this.tools,
        maxIterations: 5, // Auditors should be quick
        dangerousSkipApproval: true, // Auditors run non-interactively
      });

      const result = await runner.run();

      // Parse findings from the response
      const findings = this.parseFindings(auditor.name, result.finalResponse);
      const maxSeverity = this.getMaxSeverity(findings);

      return {
        auditorName: auditor.name,
        findings,
        transcript: result.finalResponse,
        severity: maxSeverity,
      };
    } catch (error) {
      logger.error({ error, auditor: auditor.name }, 'Auditor execution failed');
      return {
        auditorName: auditor.name,
        findings: [],
        transcript: `[ERROR: Auditor failed to execute: ${error instanceof Error ? error.message : String(error)}]`,
        severity: 'info',
      };
    }
  }

  private buildAuditorSystemPrompt(auditor: AuditorConfig): string {
    return `You are ${auditor.name}, an AI auditor with the following persona:

${auditor.persona}

Your focus areas: ${auditor.focus}

Your task is to review the agent's proposed response for potential issues. Analyze:
- Security vulnerabilities (injection attacks, exposed secrets, unsafe operations)
- Performance problems (inefficient algorithms, blocking operations, resource leaks)
- Code quality issues (anti-patterns, maintainability concerns, error handling)
- User experience problems (unclear responses, missing context, confusing explanations)

For each issue you find, report it in this format:
[SEVERITY: info|warning|critical] <description>

Examples:
[SEVERITY: critical] The proposed bash command includes unsanitized user input, creating a command injection vulnerability
[SEVERITY: warning] The response suggests installing packages globally without mentioning version pinning
[SEVERITY: info] Consider adding error handling for the file read operation

Be concise and specific. Only report genuine concerns — don't flag correct, safe code.`;
  }

  private buildAuditorUserPrompt(input: AuditorInput): string {
    const contextSnippet =
      input.conversationHistory.length > 0
        ? `\n\nConversation context (last ${Math.min(3, input.conversationHistory.length)} messages):\n${this.formatContextSnippet(input.conversationHistory)}`
        : '';

    return `Review this agent interaction:

User request:
${input.userMessage}

Agent's proposed response:
${input.proposedResponse}${contextSnippet}

Provide your critique:`;
  }

  private formatContextSnippet(history: import('../providers/types.js').Message[]): string {
    const recent = history.slice(-3);
    return recent
      .map(msg => {
        const role = msg.role === 'user' ? 'User' : 'Assistant';
        const content = typeof msg.content === 'string' ? msg.content : '[structured content]';
        return `${role}: ${content.slice(0, 200)}${content.length > 200 ? '...' : ''}`;
      })
      .join('\n\n');
  }

  private parseFindings(auditorName: string, transcript: string): AuditorFinding[] {
    const findings: AuditorFinding[] = [];
    const lines = transcript.split('\n');

    for (const line of lines) {
      const match = line.match(/\[SEVERITY:\s*(info|warning|critical)\]\s*(.+)/i);
      if (match) {
        findings.push({
          auditorName,
          severity: match[1].toLowerCase() as SeverityLevel,
          finding: match[2].trim(),
        });
      }
    }

    return findings;
  }

  private getMaxSeverity(findings: AuditorFinding[]): SeverityLevel {
    if (findings.some(f => f.severity === 'critical')) return 'critical';
    if (findings.some(f => f.severity === 'warning')) return 'warning';
    return 'info';
  }

  /**
   * Check if any auditor result exceeds the configured severity threshold
   */
  shouldBlockResponse(results: AuditorResult[], auditors: AuditorConfig[]): boolean {
    const severityRank: Record<SeverityLevel, number> = {
      info: 1,
      warning: 2,
      critical: 3,
    };

    for (const result of results) {
      const auditorConfig = auditors.find(a => a.name === result.auditorName);
      if (!auditorConfig) continue;

      const threshold = severityRank[auditorConfig.severity_threshold];
      const actual = severityRank[result.severity];

      if (actual >= threshold && result.findings.length > 0) {
        return true;
      }
    }

    return false;
  }
}

