// ── /replay ────────────────────────────────────────────────────────────────
{
  name: 'replay',
  description: 'Replay a session with messages and tool calls',
  usage: '[session_id] [--speed <1|2|4>]',
  async execute(args, ctx) {
    // Parse args for optional --speed flag
    const argsArray = args.trim().split(/\s+/).filter(Boolean);
    let sessionId = '';
    let speed = 1;

    for (let i = 0; i < argsArray.length; i++) {
      if (argsArray[i] === '--speed' && argsArray[i + 1]) {
        const speedVal = parseInt(argsArray[i + 1], 10);
        if ([1, 2, 4].includes(speedVal)) {
          speed = speedVal;
        }
        i++; // skip next arg
      } else if (!argsArray[i].startsWith('--')) {
        sessionId = argsArray[i];
      }
    }

    // If no session ID, show picker
    if (!sessionId) {
      const sessions = await listSessions(ctx.config.projectRoot, 20);
      if (sessions.length === 0) {
        console.log(chalk.dim('No sessions found.'));
        return true;
      }

      const choices = sessions.map(s => {
        const forkIndicator = s.isFork ? '🔀 ' : '';
        const labelSuffix = s.label ? chalk.dim(` [${s.label}]`) : '';
        return {
          title:
            `${forkIndicator}${chalk.cyan(s.id.slice(-8))}  ` +
            `${chalk.dim(s.updatedAt.toLocaleString())}  ` +
            chalk.dim(`${s.turnCount} turn${s.turnCount !== 1 ? 's' : ''}`) +
            labelSuffix,
          value: s.id,
          description: s.id,
        };
      });

      const response = await prompts({
        type: 'select',
        name: 'id',
        message: 'Select a session to replay:',
        choices,
        initial: 0,
      });

      if (!response.id) return true; // user cancelled
      sessionId = response.id as string;
    }

    // Load session
    const session = await getSession(sessionId, ctx.config.projectRoot);
    if (!session || session.turns.length === 0) {
      console.log(chalk.red(`Session '${sessionId}' not found or empty.`));
      return true;
    }

    // Replay session
    console.log(
      chalk.bold(`\nReplaying session ${chalk.cyan(sessionId.slice(-8))} at ${speed}x speed\n`)
    );
    await replaySession_(session.turns, speed);
    console.log(chalk.dim('\nReplay complete.\n'));

    return true;
  },
},

