{
  name: 'diff',
  description: 'Show git diff (staged + unstaged) and status',
  usage: '[--staged] [path]',
  async execute(args, ctx) {
    const argsArray = args.trim().split(/\s+/).filter(Boolean);
    const stagedOnly = argsArray.includes('--staged');
    const pathFilter = argsArray.filter(arg => arg !== '--staged').join(' ');

    const cwd = process.cwd();

    // Check if we're in a git repository
    try {
      await execFile('git', ['rev-parse', '--git-dir'], { cwd });
    } catch (error: any) {
      if (error.code === 'ENOENT') {
        console.log(chalk.yellow('\n⚠  git command not found\n'));
      } else {
        console.log(chalk.yellow('\n⚠  Not inside a git repository\n'));
      }
      return true;
    }

    let output = '';

    // Run git diff with color
    const diffArgs = stagedOnly
      ? ['diff', '--staged', '--color=always']
      : ['diff', 'HEAD', '--color=always'];

    if (pathFilter) {
      diffArgs.push('--', pathFilter);
    }

    try {
      const { stdout: diffOut } = await execFile('git', diffArgs, {
        cwd,
        encoding: 'utf8',
        maxBuffer: 10 * 1024 * 1024, // 10MB
      });
      if (diffOut) {
        output += diffOut;
      }
    } catch (error: any) {
      // git diff exits with code 1 when there are no changes or in error
      // We only care if stderr has content
      if (error.stderr && error.stderr.trim()) {
        console.log(chalk.red(`\n✗ git diff error: ${error.stderr.trim()}\n`));
        return true;
      }
      // Otherwise, empty diff is fine
    }

    // Run git status if not staged-only
    if (!stagedOnly) {
      const statusArgs = ['status', '--short'];
      if (pathFilter) {
        statusArgs.push('--', pathFilter);
      }

      try {
        const { stdout: statusOut } = await execFile('git', statusArgs, {
          cwd,
          encoding: 'utf8',
        });
        if (statusOut) {
          if (output) output += '\n';
          output += statusOut;
        }
      } catch (error: any) {
        // Status error can be silently ignored
      }
    }

    if (!output.trim()) {
      console.log(chalk.dim('\nNo changes\n'));
      return true;
    }

    // Paginate output
    const lines = output.split('\n');
    const MAX_LINES = 100;

    console.log(); // blank line before output

    if (lines.length <= MAX_LINES) {
      console.log(output);
    } else {
      console.log(lines.slice(0, MAX_LINES).join('\n'));
      console.log();
      console.log(
        chalk.dim(`[truncated — ${lines.length - MAX_LINES} more lines]`)
      );
    }

    console.log(); // blank line after output
    return true;
  },
},

