  usage: '[on|off|list]',
  async execute(args, ctx) {
    if (!ctx.auditorRegistry) {
      console.log(
        chalk.yellow('Auditors not configured — create .epam/auditors.json to enable')
      );
      return true;
    }

    const sub = args.trim().toLowerCase();

    if (sub === 'on') {
      ctx.auditorRegistry.toggle(true);
      const auditors = ctx.auditorRegistry.getEnabled();
      console.log(chalk.green(`✓ Auditors enabled — ${auditors.length} active`));
      if (auditors.length > 0) {
        console.log(chalk.dim('  Active auditors:'));
        for (const auditor of auditors) {
          console.log(
            chalk.dim(
              `    • ${chalk.cyan(auditor.name)} (${auditor.focus}) — threshold: ${auditor.severity_threshold}`
            )
          );
        }
      }
      return true;
    }

    if (sub === 'off') {
      ctx.auditorRegistry.toggle(false);
      console.log(chalk.dim('Auditors disabled'));
      return true;
    }

    if (sub === 'list' || sub === '') {
      const allAuditors = ctx.auditorRegistry.getAll();
      const isEnabled = ctx.auditorRegistry.isEnabled();

      if (allAuditors.length === 0) {
        console.log(chalk.dim('No auditors configured in .epam/auditors.json'));
        return true;
      }

      console.log(
        chalk.bold(
          `\nAuditors (${isEnabled ? chalk.green('enabled') : chalk.dim('disabled')}):\n`
        )
      );

      for (const auditor of allAuditors) {
        const status = auditor.enabled !== false && isEnabled ? chalk.green('✓') : chalk.dim('○');
        console.log(`  ${status} ${chalk.cyan.bold(auditor.name)}`);
        console.log(chalk.dim(`      Focus: ${auditor.focus}`));
        console.log(chalk.dim(`      Model: ${auditor.model}`));
        console.log(
          chalk.dim(`      Threshold: ${auditor.severity_threshold}`)
        );
        console.log();
      }

      if (!isEnabled) {
        console.log(chalk.dim('  Use /auditors on to enable auditor review\n'));
      }

      return true;
    }

    // Unknown subcommand
    console.log(chalk.yellow('Usage: /auditors [on|off|list]'));
    return true;
  },
},

