+/**
+ * Redact sensitive values from environment overrides for safe display
+ */
+function redactSecrets(envOverrides: Record<string, unknown>): Record<string, unknown> {
+  const redacted: Record<string, unknown> = {};
+  const sensitiveKeys = ['api_key', 'apikey', 'token', 'secret', 'password', 'credential'];
+
+  for (const [key, value] of Object.entries(envOverrides)) {
+    const lowerKey = key.toLowerCase();
+    const isSensitive = sensitiveKeys.some(sensitive => lowerKey.includes(sensitive));
+
+    if (isSensitive && typeof value === 'string' && value.length > 0) {
+      // Show first 4 chars and redact the rest
+      redacted[key] = value.substring(0, 4) + '***';
+    } else {
+      redacted[key] = value;
+    }
+  }
+
+  return redacted;
