+      for (const toolCall of turn.toolCalls) {
+        const argsPreview = truncateArgs_(toolCall.input);
+        console.log(
+          chalk.yellow(
+            `  ${toolCall.name}${argsPreview ? chalk.dim(` — ${argsPreview}`) : ''}`
+          )
+        );
+      }
+      console.log();
+    } else if (turn.toolCallCount > 0) {
+      // Fallback: just show count if tool calls not stored
+      console.log(
+        chalk.yellow.dim(`Tool calls: ${turn.toolCallCount} (details not available)`)
+      );
+      console.log();
+    }
+
+    // Pause between turns (except after last turn)
+    if (i < turns.length - 1) {
+      await sleep_(delayMs);
+    }
+  }
+}
+
+function getDelayForSpeed_(speed: number): number {
+  switch (speed) {
+    case 1:
+      return 2000; // 2 seconds
+    case 2:
+      return 1000; // 1 second
+    case 4:
+      return 500; // 0.5 seconds
+    default:
+      return 2000;
+  }
+}
+
+function indent_(text: string, spaces = 2): string {
+  const prefix = ' '.repeat(spaces);
+  return text
+    .split('\n')
+    .map(line => prefix + line)
+    .join('\n');
+}
+
+function truncateArgs_(input: Record<string, unknown> | undefined): string {
+  if (!input) return '';
+
+  const json = JSON.stringify(input);
+  const maxLen = 60;
+
+  if (json.length <= maxLen) return json;
+
+  return json.slice(0, maxLen) + '…';
+}
+
+function sleep_(ms: number): Promise<void> {
+  return new Promise(resolve => setTimeout(resolve, ms));
+}

