 26	  async load(): Promise<void> {
 27	    const configPath = join(this.projectRoot, '.epam', 'auditors.json');
 28	
 29	    if (!existsSync(configPath)) {
 30	      logger.debug({ configPath }, 'No auditors.json found — auditors disabled');
 31	      this.auditors = [];
 32	      return;
 33	    }
 34	
 35	    try {
 36	      const content = await readFile(configPath, 'utf-8');
 37	      const config = this.parseConfig(JSON.parse(content));
 38	
 39	      this.auditors = config.auditors.filter(a => this.isValidAuditor(a));
 40	
 41	      logger.debug({ count: this.auditors.length }, 'Loaded auditor personas');
 42	    } catch (error) {
 43	      logger.warn({ error, configPath }, 'Failed to load auditors.json');
 44	      this.auditors = [];
 45	    }
 46	  }
