 61	  getRunnerByName(
 62	    name: string,
 63	    provider: LLMProvider,
 64	    tools: Tool[],
 65	  ): AuditorRunner | undefined {
 66	    const auditor = this.auditors.find(candidate => candidate.name === name);
 67	    return auditor ? new AuditorRunner(auditor, provider, tools) : undefined;
 68	  }
