 82	  private parseConfig(rawConfig: unknown): AuditorConfigFile {
 83	    if (Array.isArray(rawConfig)) {
 84	      return { auditors: rawConfig as AuditorConfig[] };
 85	    }
 86	
 87	    if (
 88	      rawConfig &&
 89	      typeof rawConfig === 'object' &&
 90	      Array.isArray((rawConfig as Partial<AuditorConfigFile>).auditors)
 91	    ) {
 92	      return rawConfig as AuditorConfigFile;
 93	    }
 94	
 95	    logger.warn('auditors.json must be an array or an object with an "auditors" array');
 96	    return { auditors: [] };
 97	  }
