 13	const DEFAULT_MAX_TOOL_OUTPUT_CHARS = 32_768;
 14	const DEFAULT_AUTO_COMPRESS_AT = 80_000;
 15	const DEFAULT_MAX_OUTPUT_TOKENS = 16_384;
 16	
 17	interface AuditorAwareAgentRunOptions extends AgentRunOptions {
 18	  onAuditorFindings?: (results: AuditorResult[]) => void | Promise<void>;
 19	  onAuditorGate?: (results: AuditorResult[]) => Promise<boolean>;
