 22	/**
 23	 * AgentRunner executes the ReAct agent loop.
 24	 *
 25	 * Remote constraints should be loaded before session start and injected into the
 26	 * system prompt via ContextBuilder. See ConstraintLoader for fetching constraints
 27	 * from the backend at GET /v1/projects/{id}/constraints.
 28	 */
 29	
 30	function estimateTokens(messages: Message[]): number {
 31	  let chars = 0;
 32	  for (const m of messages) {
 33	    if (typeof m.content === 'string') {
 34	      chars += m.content.length;
 35	    } else {
 36	      chars += JSON.stringify(m.content).length;
 37	    }
 38	  }
 39	  return Math.ceil(chars / 4);
 40	}
 41	
 42	function truncateToolOutput(content: string, limit: number): string {
 43	  if (content.length <= limit) return content;
 44	  const kept = content.slice(0, limit);
 45	  const droppedChars = content.length - limit;
 46	  return `${kept}\n\n[truncated — showing first ${limit.toLocaleString()} of ${content.length.toLocaleString()} chars (${droppedChars.toLocaleString()} dropped)]`;
 47	}
 48	
 49	export class AgentRunner {
 50	  private executor: Executor;
 51	  private iterationCount = 0;
 52	  private totalInputTokens = 0;
 53	  private totalOutputTokens = 0;
 54	  private totalToolCalls = 0;
 55	  private maxToolOutputChars: number;
 56	
 57	  constructor(private options: AgentRunOptions) {
 58	    this.executor = new Executor({
 59	      tools: options.tools,
 60	      dangerousSkipApproval: options.dangerousSkipApproval ?? false,
 61	      maxConcurrency: 3,
 62	    });
 63	    this.maxToolOutputChars = options.maxToolOutputChars ?? DEFAULT_MAX_TOOL_OUTPUT_CHARS;
 64	  }
 65	
 66	  async run(): Promise<AgentRunResult> {
 67	    const maxIterations = this.options.maxIterations ?? 20;
 68	    const autoCompressAt = this.options.autoCompressAt ?? DEFAULT_AUTO_COMPRESS_AT;
 69	
 70	    let messages: Message[] = [
 71	      ...(this.options.history ?? []),
 72	      { role: 'user', content: this.options.userMessage },
 73	    ];
 74	
 75	    let finalResponse = '';
 76	
 77	    while (this.iterationCount < maxIterations) {
 78	      this.iterationCount++;
 79	      this.options.onIterationStart?.(this.iterationCount);
 80	
 81	      logger.debug({ iteration: this.iterationCount }, 'Agent iteration');
 82	
 83	      // Auto-compress if history has grown past threshold
 84	      if (estimateTokens(messages) > autoCompressAt && messages.length > 6) {
 85	        try {
 86	          logger.debug('Auto-compressing conversation history');
 87	          messages = await compressHistory(
 88	            messages,
 89	            this.options.provider,
 90	            this.options.model,
 91	          );
 92	        } catch {
 93	          logger.warn('Auto-compression failed, continuing with full history');
 94	        }
 95	      }
 96	
 97	      let accumulatedText = '';
 98	
 99	      const response = await this.options.provider.stream(
100	        {
101	          messages,
102	          systemPrompt: this.options.systemPrompt,
103	          tools: this.options.tools.map(t => t.definition),
104	          model: this.options.model,
105	          stream: true,
106	          maxTokens: this.options.maxOutputTokens ?? DEFAULT_MAX_OUTPUT_TOKENS,
107	        },
108	        delta => {
109	          if (delta.type === 'text_delta') {
110	            this.options.onTextDelta?.(delta.text);
111	            accumulatedText += delta.text;
112	          }
113	        }
114	      );
115	
116	      this.totalInputTokens += response.usage.inputTokens;
117	      this.totalOutputTokens += response.usage.outputTokens;
118	
119	      // Budget enforcement — check after every LLM response
120	      if (this.options.budgetGuard) {
121	        const check = this.options.budgetGuard.recordUsage(
122	          response.usage.inputTokens,
123	          response.usage.outputTokens,
124	        );
125	        if (check.action !== 'ok') {
126	          this.options.onBudgetCheck?.(check);
127	        }
128	        if (check.action === 'pause') {
129	          // Hard stop — append what we have and return immediately
130	          messages.push({ role: 'assistant', content: response.content });
131	          return this.buildResult(
132	            response.content.filter(p => p.type === 'text').map(p => p.text ?? '').join('') || check.message,
133	            messages,
134	          );
135	        }
136	      }
137	
138	      const toolUses = response.content.filter(p => p.type === 'tool_use');
139	      const textParts = response.content.filter(p => p.type === 'text');
140	
141	      if (textParts.length > 0 || accumulatedText) {
142	        finalResponse = textParts.map(p => p.text ?? '').join('') || accumulatedText;
143	      }
144	
145	      if (response.stopReason === 'end_turn' || toolUses.length === 0) {
146	        // Append the final assistant message so messages array is complete
147	        messages.push({ role: 'assistant', content: response.content });
148	
149	        if (finalResponse) {
150	          const shouldProceed = await this.reviewWithAuditors(finalResponse, messages);
151	          if (!shouldProceed) {
152	            return this.buildResult('[Response blocked by auditor review]', messages);
153	          }
154	        }
155	
156	        break;
157	      }
158	
159	      if (response.stopReason === 'max_tokens') {
160	        // Model ran out of output tokens mid-generation — push what we have
161	        // and continue the loop so the model can pick up where it left off.
162	        logger.debug('max_tokens hit — continuing conversation');
163	        messages.push({ role: 'assistant', content: response.content });
164	        messages.push({ role: 'user', content: 'Continue from where you left off.' });
165	        continue;
166	      }
167	
168	      const toolCallRequests: ToolCallRequest[] = toolUses.map(p => ({
169	        id: p.id ?? '',
170	        name: p.name ?? '',
171	        input: (p.input as Record<string, unknown>) ?? {},
172	      }));
173	
174	      this.totalToolCalls += toolCallRequests.length;
175	      this.options.onToolCall?.(
176	        toolCallRequests.map(r => r.name).join(', '),
177	        toolCallRequests[0]?.input ?? {}
178	      );
179	
180	      const toolResults = await this.executor.executeAll(toolCallRequests);
181	
182	      for (const result of toolResults) {
183	        result.content = truncateToolOutput(result.content, this.maxToolOutputChars);
184	
185	        this.options.onToolResult?.(
186	          toolCallRequests.find(r => r.id === result.toolUseId)?.name ?? '',
187	          result.content,
188	          result.isError
189	        );
190	      }
191	
192	      messages.push({
193	        role: 'assistant',
194	        content: response.content,
195	      });
196	
197	      messages.push({
198	        role: 'tool',
199	        content: toolResults.map(r => ({
200	          type: 'tool_result' as const,
201	          tool_use_id: r.toolUseId,
202	          content: r.content,
203	        })),
204	      });
205	    }
206	
207	    if (this.iterationCount >= maxIterations && !finalResponse) {
208	      finalResponse = `Agent reached maximum iterations (${maxIterations}) without completing.`;
209	    }
210	
211	    return this.buildResult(finalResponse, messages);
212	  }
213	
214	  private buildResult(finalResponse: string, messages: Message[]): AgentRunResult {
215	    return {
216	      finalResponse,
217	      toolCallCount: this.totalToolCalls,
218	      iterations: this.iterationCount,
219	      usage: {
220	        inputTokens: this.totalInputTokens,
221	        outputTokens: this.totalOutputTokens,
222	      },
223	      messages,
224	    };
225	  }
226	
227	  private async reviewWithAuditors(
228	    finalResponse: string,
229	    messages: Message[],
230	  ): Promise<boolean> {
231	    if (this.options.onAuditorReview) {
232	      return this.options.onAuditorReview(
233	        this.options.userMessage,
234	        finalResponse,
235	        messages,
236	      );
237	    }
238	
239	    const registry = AuditorRegistry.getActive();
240	    if (!registry || !registry.isEnabled()) {
241	      return true;
242	    }
243	
244	    const runners = registry.getEnabledRunners(this.options.provider, this.options.tools);
245	    if (runners.length === 0) {
246	      return true;
247	    }
248	
249	    logger.debug({ auditorCount: runners.length }, 'Running enabled auditors');
250	
251	    const results = await Promise.all(
252	      runners.map(runner =>
253	        runner.run({
254	          userMessage: this.options.userMessage,
255	          proposedResponse: finalResponse,
256	          conversationHistory: messages,
257	        }),
258	      ),
259	    );
260	
261	    await this.emitAuditorFindings(results);
262	
263	    const gateDecision = AuditorRunner.evaluateGate(results, runners);
264	    if (!gateDecision.blocked) {
265	      return true;
266	    }
267	
268	    return this.promptForAuditorGate(results);
269	  }
270	
271	  private async emitAuditorFindings(results: AuditorResult[]): Promise<void> {
272	    const options = this.options as AuditorAwareAgentRunOptions;
273	    if (options.onAuditorFindings) {
274	      await options.onAuditorFindings(results);
275	      return;
276	    }
277	
278	    for (const result of results) {
279	      if (result.findings.length === 0) {
280	        console.log(
281	          chalk.magenta(
282	            `[AUDITOR: ${result.auditorName}] Finding: ${result.transcript || 'No findings.'}`
283	          )
284	        );
285	        continue;
286	      }
287	
288	      for (const finding of result.findings) {
289	        console.log(
290	          chalk.magenta(
291	            `[AUDITOR: ${result.auditorName}] Finding: (${finding.severity}) ${finding.finding}`
292	          )
293	        );
294	      }
295	    }
296	  }
297	
298	  private async promptForAuditorGate(results: AuditorResult[]): Promise<boolean> {
299	    const options = this.options as AuditorAwareAgentRunOptions;
300	    if (options.onAuditorGate) {
301	      return options.onAuditorGate(results);
302	    }
303	
304	    const blockingSummary = results
305	      .filter(result => result.findings.length > 0)
306	      .map(result => `${result.auditorName}:${result.severity}`)
307	      .join(', ');
308	
309	    console.log(
310	      chalk.magenta(
311	        `Auditor gate triggered. Findings at or above threshold: ${blockingSummary}`
312	      )
313	    );
314	
315	    const decision = await prompts({
316	      type: 'select',
317	      name: 'action',
318	      message: 'Proceed with the proposed response?',
319	      choices: [
320	        { title: 'Proceed', value: 'proceed' },
321	        { title: 'Reject', value: 'reject' },
322	      ],
323	      initial: 1,
324	    });
325	
326	    return decision.action === 'proceed';
327	  }
328	}

  1	import type { LLMProvider, Message } from '../providers/types.js';
  2	import type { Tool } from '../tools/types.js';
  3	import type {
  4	  AuditorConfig,
  5	  AuditorFinding,
  6	  AuditorGateDecision,
  7	  AuditorInput,
  8	  AuditorResult,
  9	  SeverityLevel,
 10	} from './types.js';
 11	import { SEVERITY_RANK } from './types.js';
 12	import { AgentRunner } from '../agent/AgentRunner.js';
 13	import { logger } from '../utils/logger.js';
 14	
 15	/**
 16	 * Executes a single persona-specific auditor against a proposed agent response.
 17	 */
 18	export class AuditorRunner {
 19	  readonly name: string;
 20	
 21	  constructor(
 22	    readonly config: AuditorConfig,
 23	    private provider: LLMProvider,
 24	    private tools: Tool[],
 25	  ) {
 26	    this.name = config.name;
 27	  }
 28	
 29	  async run(input: AuditorInput): Promise<AuditorResult> {
 30	    try {
 31	      const runner = new AgentRunner({
 32	        userMessage: this.buildAuditorUserPrompt(input),
 33	        systemPrompt: this.buildAuditorSystemPrompt(),
 34	        provider: this.provider,
 35	        model: this.config.model,
 36	        tools: this.tools,
 37	        maxIterations: 5,
 38	        dangerousSkipApproval: true,
 39	      });
 40	
 41	      const result = await runner.run();
 42	      const findings = this.parseFindings(result.finalResponse);
 43	
 44	      return {
 45	        auditorName: this.config.name,
 46	        findings,
 47	        transcript: result.finalResponse,
 48	        severity: this.getMaxSeverity(findings),
 49	      };
 50	    } catch (error) {
 51	      logger.error({ error, auditor: this.config.name }, 'Auditor execution failed');
 52	      return {
 53	        auditorName: this.config.name,
 54	        findings: [],
 55	        transcript: `[ERROR] Auditor failed to execute: ${error instanceof Error ? error.message : String(error)}`,
 56	        severity: 'info',
 57	      };
 58	    }
 59	  }
 60	
 61	  exceedsThreshold(result: AuditorResult): boolean {
 62	    return (
 63	      result.findings.length > 0 &&
 64	      SEVERITY_RANK[result.severity] >= SEVERITY_RANK[this.config.severity_threshold]
 65	    );
 66	  }
 67	
 68	  static evaluateGate(results: AuditorResult[], runners: AuditorRunner[]): AuditorGateDecision {
 69	    const runnerByName = new Map(runners.map(runner => [runner.name, runner]));
 70	    const blockingAuditors = results.filter(result => runnerByName.get(result.auditorName)?.exceedsThreshold(result));
 71	
 72	    return {
 73	      blocked: blockingAuditors.length > 0,
 74	      blockingAuditors,
 75	    };
 76	  }
 77	
 78	  private buildAuditorSystemPrompt(): string {
 79	    return [
 80	      `You are ${this.config.name}.`,
 81	      `Persona: ${this.config.persona}`,
 82	      `Primary focus: ${this.config.focus}`,
 83	      '',
 84	      'Audit the assistant response for issues that matter to your persona and focus area.',
 85	      'You are reviewing a candidate answer before it is shown to the user.',
 86	      'Consider correctness, safety, omissions, weak assumptions, and conflicts with the conversation context.',
 87	      '',
 88	      'Output one finding per line using exactly this format:',
 89	      '[SEVERITY: info|warning|critical] <finding>',
 90	      '',
 91	      'If there are no issues, return:',
 92	      '[SEVERITY: info] No findings.',
 93	      '',
 94	      'Be concise, concrete, and avoid generic advice.',
 95	    ].join('\n');
 96	  }
 97	
 98	  private buildAuditorUserPrompt(input: AuditorInput): string {
 99	    return [
100	      'Review this interaction before the answer is confirmed.',
101	      '',
102	      'User message:',
103	      input.userMessage,
104	      '',
105	      'Proposed assistant response:',
106	      input.proposedResponse,
107	      '',
108	      'Full conversation context:',
109	      this.formatConversationHistory(input.conversationHistory),
110	    ].join('\n');
111	  }
112	
113	  private formatConversationHistory(history: Message[]): string {
114	    if (history.length === 0) {
115	      return '[no prior context]';
116	    }
117	
118	    return history
119	      .map(message => {
120	        const role = message.role.toUpperCase();
121	        const content =
122	          typeof message.content === 'string'
123	            ? message.content
124	            : JSON.stringify(message.content);
125	        return `${role}: ${content}`;
126	      })
127	      .join('\n\n');
128	  }
129	
130	  private parseFindings(transcript: string): AuditorFinding[] {
131	    const findings: AuditorFinding[] = [];
132	
133	    for (const line of transcript.split('\n')) {
134	      const match = line.match(/\[SEVERITY:\s*(info|warning|critical)\]\s*(.+)/i);
135	      if (!match) {
136	        continue;
137	      }
138	
139	      findings.push({
140	        auditorName: this.config.name,
141	        severity: match[1].toLowerCase() as SeverityLevel,
142	        finding: match[2].trim(),
143	      });
144	    }
145	
146	    return findings;
147	  }
148	
149	  private getMaxSeverity(findings: AuditorFinding[]): SeverityLevel {
150	    if (findings.some(finding => finding.severity === 'critical')) {
151	      return 'critical';
152	    }
153	
154	    if (findings.some(finding => finding.severity === 'warning')) {
